/**
 * @summary Trim, caption, and convert video to Reels format
 */
export const getProcessVideoUrl = () => {
  return `/api/video/process`;
};

export const processVideo = async (
  processVideoRequest: ProcessVideoRequest,
  options?: RequestInit,
): Promise<ProcessedVideo> => {
  const formData = new FormData();
  if (processVideoRequest.startSeconds !== undefined) {
    formData.append(
      `startSeconds`,
      processVideoRequest.startSeconds.toString(),
    );
  }
  if (processVideoRequest.endSeconds !== undefined) {
    formData.append(`endSeconds`, processVideoRequest.endSeconds.toString());
  }
  if (processVideoRequest.addCaptions !== undefined) {
    formData.append(`addCaptions`, processVideoRequest.addCaptions.toString());
  }
  if (processVideoRequest.convertToReels !== undefined) {
    formData.append(
      `convertToReels`,
      processVideoRequest.convertToReels.toString(),
    );
  }
  formData.append(`video`, processVideoRequest.video);

  return customFetch<ProcessedVideo>(getProcessVideoUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

export const getProcessVideoMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof processVideo>>,
    TError,
    { data: BodyType<ProcessVideoRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof processVideo>>,
  TError,
  { data: BodyType<ProcessVideoRequest> },
  TContext
> => {
  const mutationKey = ["processVideo"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof processVideo>>,
    { data: BodyType<ProcessVideoRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return processVideo(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ProcessVideoMutationResult = NonNullable<
  Awaited<ReturnType<typeof processVideo>>
>;
export type ProcessVideoMutationBody = BodyType<ProcessVideoRequest>;
export type ProcessVideoMutationError = ErrorType<unknown>;

